import React, { useState } from 'react';
import Home from './pages/Home';
import Login from './pages/Login';
import 'bootstrap/dist/css/bootstrap.min.css';

function App() {
  const [currentPage, setCurrentPage] = useState('home');

  // Tumchi ti original background image style
  const backgroundStyle = {
    backgroundImage: `linear-gradient(rgba(0, 0, 0, 0.6), rgba(0, 0, 0, 0.6)), url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?auto=format&fit=crop&q=80&w=2000')`,
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundAttachment: 'fixed',
    minHeight: '100vh',
    width: '100%'
  };

  return (
    <div style={backgroundStyle}>
      {/* Varcha Professional Blue Navbar */}
      <nav className="navbar navbar-expand-lg navbar-dark px-4 shadow" style={{ backgroundColor: '#0056b3' }}>
        <div className="container-fluid">
          <span className="navbar-brand fw-bold fs-3" style={{ cursor: 'pointer' }} onClick={() => setCurrentPage('home')}>
            APNI MANZIL
          </span>
          <div className="ms-auto">
            <button 
              onClick={() => setCurrentPage(currentPage === 'home' ? 'login' : 'home')} 
              className="btn btn-success rounded-pill px-4 fw-bold shadow-sm"
            >
              {currentPage === 'home' ? 'Login / Sign Up' : 'Back to Home'}
            </button>
          </div>
        </div>
      </nav>

      {/* Main Content: Home kiwa Login */}
      <main className="pb-5">
        {currentPage === 'home' ? <Home /> : <Login />}
      </main>

      <footer className="text-center py-4 text-white-50 small">
        © 2026 Apni Manzil | All-in-One Logistics Solution
      </footer>
    </div>
  );
}

export default App;
